import type { AxisIdToScales } from '../../../context/XYChartScales.context.js';
import type { MapDatapoints } from '../../../types/xy-chart-internals.js';
import type {
  AreaDatapoint,
  DotDatapoint,
  LineDatapoint,
} from '../../../types/xy-chart.js';
import { getCurrentScale } from '../../../utils/get-scale.js';
import {
  xAccessor as areaXAccessor,
  x1Accessor as areaX1Accessor,
  y1Accessor as areaY1Accessor,
  yAccessor as areaYAccessor,
} from '../../displays/area-accessors.js';
import {
  xAccessor as dotXAccessor,
  yAccessor as dotYAccessor,
} from '../../displays/dot-accessors.js';

type Position = { x: number; y: number };
type Datapoint = DotDatapoint | LineDatapoint | AreaDatapoint;

export interface CalculateCrosshairCoordinatesInput {
  pinned: boolean;
  tooltipContentHasCenteredCrosshair: boolean;
  tooltipContentSeries: { xAxisId: string; yAxisId: string };
  datapoint: Datapoint;
  axisIdToScales: AxisIdToScales;
  datapointMetadataMap: MapDatapoints;
  xRelAccessor: ((value: number) => number) | undefined;
  yRelAccessor: ((value: number) => number) | undefined;
  isArea: boolean;
  isHorizontal: boolean;
  isStacked: boolean | undefined;
}

/**
 * Calculates crosshair coordinates for a datapoint on the chart.
 * Optimized for high-frequency calls during mouse movement.
 *
 * @param input - Coordinate calculation parameters
 * @returns Position to render the crosshair at
 */
export function calculateCrosshairCoordinates({
  tooltipContentSeries,
  datapoint,
  axisIdToScales,
  datapointMetadataMap,
  xRelAccessor,
  yRelAccessor,
  isArea,
  isHorizontal,
  isStacked,
}: Readonly<CalculateCrosshairCoordinatesInput>): Position {
  const xScale = getCurrentScale(axisIdToScales, tooltipContentSeries.xAxisId);
  const yScale = getCurrentScale(axisIdToScales, tooltipContentSeries.yAxisId);

  let x: number;
  if (isArea) {
    x = isHorizontal
      ? areaX1Accessor(
          xScale,
          datapointMetadataMap,
          xRelAccessor,
          isStacked,
        )(datapoint as AreaDatapoint)
      : areaXAccessor(xScale, xRelAccessor)(datapoint as AreaDatapoint);
  } else {
    x = dotXAccessor(
      xScale,
      xRelAccessor,
    )(datapoint as DotDatapoint | LineDatapoint);
  }

  let y: number;
  if (isArea) {
    y = isHorizontal
      ? areaYAccessor(yScale, yRelAccessor)(datapoint as AreaDatapoint)
      : areaY1Accessor(
          yScale,
          datapointMetadataMap,
          yRelAccessor,
          isStacked,
        )(datapoint as AreaDatapoint);
  } else {
    y = dotYAccessor(
      yScale,
      yRelAccessor,
    )(datapoint as DotDatapoint | LineDatapoint);
  }

  return { x, y };
}
